{"path": "/tmp/sv-4278b123e4484339ac5f498e813591a9/Components/Settings/SettingsSidebar.razor", "file_text": "<nav class="settings-sidebar">
    <ul class="nav flex-column">
        @foreach (var section in Sections)
        {
            <li class="nav-item">
                <button class="nav-link @(section == ActiveSection ? "active" : "")"
                        @onclick="() => OnSectionChanged.InvokeAsync(section)">
                    <span class="sidebar-icon">@GetIcon(section)</span>
                    @section
                </button>
            </li>
        }
    </ul>
</nav>

@code {
    [Parameter, EditorRequired] public string ActiveSection { get; set; } = "";
    [Parameter, EditorRequired] public EventCallback<string> OnSectionChanged { get; set; }

    private static readonly string[] Sections = ["Profile", "Notifications", "Security", "Appearance"];

    private static string GetIcon(string section) => section switch
    {
        "Profile" => "👤",
        "Notifications" => "🔔",
        "Security" => "🔒",
        "Appearance" => "🎨",
        _ => "⚙️"
    };
}
"}

{"path": "/tmp/sv-4278b123e4484339ac5f498e813591a9/Components/Settings/ProfileSection.razor", "file_text": "<div class="settings-section">
    <h3>Profile Settings</h3>
    <hr />

    @if (Profile is null)
    {
        <p>Loading profile...</p>
        return;
    }

    <div class="row mb-4">
        <div class="col-md-3 text-center">
            <div class="avatar-preview mb-2">
                @if (!string.IsNullOrEmpty(editAvatarUrl))
                {
                    <img src="@editAvatarUrl" alt="Avatar" class="rounded-circle" style="width:100px;height:100px;object-fit:cover;" />
                }
                else
                {
                    <div class="rounded-circle bg-secondary d-flex align-items-center justify-content-center"
                         style="width:100px;height:100px;margin:0 auto;">
                        <span class="text-white fs-3">@(editDisplayName?.FirstOrDefault())</span>
                    </div>
                }
            </div>
            <small class="text-muted text-break">@editAvatarUrl</small>
        </div>
        <div class="col-md-9">
            <div class="mb-3">
                <label class="form-label">Display Name</label>
                <input class="form-control" @bind="editDisplayName" />
            </div>
            <div class="mb-3">
                <label class="form-label">Email</label>
                <input class="form-control" type="email" @bind="editEmail" />
            </div>
            <div class="mb-3">
                <label class="form-label">Avatar URL</label>
                <input class="form-control" @bind="editAvatarUrl" />
            </div>
            <div class="mb-3">
                <label class="form-label">Bio</label>
                <textarea class="form-control" rows="3" @bind="editBio"></textarea>
            </div>
        </div>
    </div>

    <div class="d-flex gap-2">
        <button class="btn btn-primary" @onclick="SaveAsync" disabled="@saving">
            @(saving ? "Saving..." : "Save Changes")
        </button>
        <button class="btn btn-outline-secondary" @onclick="Discard" disabled="@saving">
            Discard Changes
        </button>
    </div>

    @if (!string.IsNullOrEmpty(statusMessage))
    {
        <div class="alert @(isError ? "alert-danger" : "alert-success") mt-3 fade show" role="alert">
            @statusMessage
        </div>
    }
</div>

@code {
    [Parameter, EditorRequired] public UserProfile? Profile { get; set; }
    [Parameter, EditorRequired] public EventCallback<UserProfile> OnSave { get; set; }

    private string editDisplayName = "";
    private string editEmail = "";
    private string editAvatarUrl = "";
    private string editBio = "";
    private bool saving;
    private string? statusMessage;
    private bool isError;

    protected override void OnParametersSet()
    {
        if (Profile is not null && !saving)
        {
            LoadFromProfile();
        }
    }

    private void LoadFromProfile()
    {
        editDisplayName = Profile!.DisplayName;
        editEmail = Profile.Email;
        editAvatarUrl = Profile.AvatarUrl;
        editBio = Profile.Bio;
    }

    private async Task SaveAsync()
    {
        saving = true;
        statusMessage = null;
        try
        {
            var updated = new UserProfile(editDisplayName, editEmail, editAvatarUrl, editBio);
            await OnSave.InvokeAsync(updated);
            statusMessage = "Profile saved successfully!";
            isError = false;
        }
        catch
        {
            statusMessage = "Failed to save profile.";
            isError = true;
        }
        finally
        {
            saving = false;
        }
    }

    private void Discard()
    {
        LoadFromProfile();
        statusMessage = null;
    }
}
"}

{"path": "/tmp/sv-4278b123e4484339ac5f498e813591a9/Components/Settings/NotificationsSection.razor", "file_text": "<div class="settings-section">
    <h3>Notification Preferences</h3>
    <hr />

    @if (Prefs is null)
    {
        <p>Loading preferences...</p>
        return;
    }

    <div class="mb-4">
        <div class="form-check form-switch mb-3">
            <input class="form-check-input" type="checkbox" id="emailNotif"
                   checked="@editEmailNotifications"
                   @onchange="e => editEmailNotifications = (bool)e.Value!" />
            <label class="form-check-label" for="emailNotif">Email Notifications</label>
        </div>
        <div class="form-check form-switch mb-3">
            <input class="form-check-input" type="checkbox" id="pushNotif"
                   checked="@editPushNotifications"
                   @onchange="e => editPushNotifications = (bool)e.Value!" />
            <label class="form-check-label" for="pushNotif">Push Notifications</label>
        </div>
        <div class="form-check form-switch mb-3">
            <input class="form-check-input" type="checkbox" id="weeklyDigest"
                   checked="@editWeeklyDigest"
                   @onchange="e => editWeeklyDigest = (bool)e.Value!" />
            <label class="form-check-label" for="weeklyDigest">Weekly Digest</label>
        </div>
    </div>

    @if (editMutedChannels.Count > 0)
    {
        <h5>Channels</h5>
        <div class="mb-4">
            @foreach (var channel in editMutedChannels)
            {
                <div class="form-check mb-2">
                    <input class="form-check-input" type="checkbox" id="@($"ch-{channel.Name}")"
                           checked="@channel.IsMuted"
                           @onchange="e => channel.IsMuted = (bool)e.Value!" />
                    <label class="form-check-label" for="@($"ch-{channel.Name}")">
                        Mute "@channel.Name"
                    </label>
                </div>
            }
        </div>
    }

    <button class="btn btn-primary" @onclick="SaveAsync" disabled="@saving">
        @(saving ? "Saving..." : "Save Preferences")
    </button>

    @if (!string.IsNullOrEmpty(statusMessage))
    {
        <div class="alert alert-success mt-3" role="alert">@statusMessage</div>
    }
</div>

@code {
    [Parameter, EditorRequired] public NotificationPrefs? Prefs { get; set; }
    [Parameter, EditorRequired] public EventCallback<NotificationPrefs> OnSave { get; set; }

    private bool editEmailNotifications;
    private bool editPushNotifications;
    private bool editWeeklyDigest;
    private List<MutableChannel> editMutedChannels = [];
    private bool saving;
    private string? statusMessage;

    protected override void OnParametersSet()
    {
        if (Prefs is not null && !saving)
        {
            editEmailNotifications = Prefs.EmailNotifications;
            editPushNotifications = Prefs.PushNotifications;
            editWeeklyDigest = Prefs.WeeklyDigest;
            editMutedChannels = Prefs.MutedChannels
                .Select(c => new MutableChannel { Name = c, IsMuted = true })
                .ToList();
        }
    }

    private async Task SaveAsync()
    {
        saving = true;
        statusMessage = null;
        var mutedList = editMutedChannels.Where(c => c.IsMuted).Select(c => c.Name).ToList();
        var updated = new NotificationPrefs(editEmailNotifications, editPushNotifications, editWeeklyDigest, mutedList);
        await OnSave.InvokeAsync(updated);
        statusMessage = "Preferences saved!";
        saving = false;
    }

    private class MutableChannel
    {
        public string Name { get; set; } = "";
        public bool IsMuted { get; set; }
    }
}
"}

{"path": "/tmp/sv-4278b123e4484339ac5f498e813591a9/Components/Settings/ChangePasswordPanel.razor", "file_text": "<div class="card mb-4">
    <div class="card-header d-flex justify-content-between align-items-center"
         style="cursor:pointer" @onclick="() => isExpanded = !isExpanded">
        <strong>Change Password</strong>
        <span>@(isExpanded ? "▲" : "▼")</span>
    </div>
    @if (isExpanded)
    {
        <div class="card-body">
            <div class="mb-3">
                <label class="form-label">Current Password</label>
                <input class="form-control" type="password" @bind="currentPassword" />
            </div>
            <div class="mb-3">
                <label class="form-label">New Password</label>
                <input class="form-control" type="password" @bind="newPassword" />
            </div>
            <div class="mb-3">
                <label class="form-label">Confirm New Password</label>
                <input class="form-control" type="password" @bind="confirmPassword" />
            </div>

            @if (!string.IsNullOrEmpty(errorMessage))
            {
                <div class="alert alert-danger">@errorMessage</div>
            }
            @if (!string.IsNullOrEmpty(successMessage))
            {
                <div class="alert alert-success">@successMessage</div>
            }

            <button class="btn btn-warning" @onclick="SubmitAsync" disabled="@submitting">
                @(submitting ? "Updating..." : "Update Password")
            </button>
        </div>
    }
</div>

@code {
    [Parameter, EditorRequired]
    public EventCallback<(string CurrentPassword, string NewPassword)> OnChangePassword { get; set; }

    private string currentPassword = "";
    private string newPassword = "";
    private string confirmPassword = "";
    private string? errorMessage;
    private string? successMessage;
    private bool submitting;
    private bool isExpanded;

    private async Task SubmitAsync()
    {
        errorMessage = null;
        successMessage = null;

        if (string.IsNullOrWhiteSpace(currentPassword) ||
            string.IsNullOrWhiteSpace(newPassword))
        {
            errorMessage = "All password fields are required.";
            return;
        }

        if (newPassword != confirmPassword)
        {
            errorMessage = "New password and confirmation do not match.";
            return;
        }

        submitting = true;
        try
        {
            await OnChangePassword.InvokeAsync((currentPassword, newPassword));
            successMessage = "Password updated successfully!";
            currentPassword = "";
            newPassword = "";
            confirmPassword = "";
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to change password: {ex.Message}";
        }
        finally
        {
            submitting = false;
        }
    }
}
"}

{"path": "/tmp/sv-4278b123e4484339ac5f498e813591a9/Components/Settings/ActiveSessionsTable.razor", "file_text": "<div class="card">
    <div class="card-header"><strong>Active Sessions</strong></div>
    <div class="card-body p-0">
        @if (Sessions is null || Sessions.Count == 0)
        {
            <p class="p-3 mb-0 text-muted">No active sessions.</p>
        }
        else
        {
            <div class="table-responsive">
                <table class="table table-hover mb-0">
                    <thead>
                        <tr>
                            <th>Device</th>
                            <th>Location</th>
                            <th>Last Active</th>
                            <th></th>
                        </tr>
                    </thead>
                    <tbody>
                        @foreach (var session in Sessions)
                        {
                            <tr>
                                <td>@session.Device</td>
                                <td>@session.Location</td>
                                <td>@session.LastActive.ToString("g")</td>
                                <td>
                                    @if (session.Id != CurrentSessionId)
                                    {
                                        @if (confirmingSessionId == session.Id)
                                        {
                                            <span class="me-2 text-danger">Revoke this session?</span>
                                            <button class="btn btn-danger btn-sm me-1"
                                                    @onclick="() => ConfirmRevokeAsync(session.Id)">
                                                Yes
                                            </button>
                                            <button class="btn btn-outline-secondary btn-sm"
                                                    @onclick="() => confirmingSessionId = null">
                                                No
                                            </button>
                                        }
                                        else
                                        {
                                            <button class="btn btn-outline-danger btn-sm"
                                                    @onclick="() => confirmingSessionId = session.Id">
                                                Revoke
                                            </button>
                                        }
                                    }
                                    else
                                    {
                                        <span class="badge bg-success">Current</span>
                                    }
                                </td>
                            </tr>
                        }
                    </tbody>
                </table>
            </div>
        }
    </div>
</div>

@code {
    [Parameter, EditorRequired] public List<ActiveSession>? Sessions { get; set; }
    [Parameter] public string? CurrentSessionId { get; set; }
    [Parameter, EditorRequired] public EventCallback<string> OnRevoke { get; set; }

