{"path": "/tmp/sv-4278b123e4484339ac5f498e813591a9/Components/Settings/AppearanceSection.razor", "file_text": "<div class="settings-section">
    <h3>Appearance Settings</h3>
    <hr />

    @if (Settings is null)
    {
        <p>Loading appearance settings...</p>
        return;
    }

    <div class="row">
        <div class="col-md-6">
            <div class="mb-4">
                <h5>Theme</h5>
                @foreach (var theme in new[] { "Light", "Dark", "System" })
                {
                    <div class="form-check">
                        <input class="form-check-input" type="radio" name="theme"
                               id="@($"theme-{theme}")" value="@theme"
                               checked="@(editTheme == theme)"
                               @onchange="() => editTheme = theme" />
                        <label class="form-check-label" for="@($"theme-{theme}")">@theme</label>
                    </div>
                }
            </div>

            <div class="mb-4">
                <h5>Font Size</h5>
                @foreach (var size in new[] { "Small", "Medium", "Large" })
                {
                    <div class="form-check">
                        <input class="form-check-input" type="radio" name="fontSize"
                               id="@($"fs-{size}")" value="@size"
                               checked="@(editFontSize == size)"
                               @onchange="() => editFontSize = size" />
                        <label class="form-check-label" for="@($"fs-{size}")">@size</label>
                    </div>
                }
            </div>

            <div class="mb-4">
                <h5>Language</h5>
                <select class="form-select" @bind="editLanguage">
                    <option value="en">English</option>
                    <option value="es">Español</option>
                    <option value="fr">Français</option>
                    <option value="de">Deutsch</option>
                    <option value="ja">日本語</option>
                    <option value="zh">中文</option>
                </select>
            </div>

            <div class="mb-4">
                <div class="form-check form-switch">
                    <input class="form-check-input" type="checkbox" id="compactMode"
                           checked="@editCompactMode"
                           @onchange="e => editCompactMode = (bool)e.Value!" />
                    <label class="form-check-label" for="compactMode">Compact Mode</label>
                </div>
            </div>

            <button class="btn btn-primary" @onclick="SaveAsync" disabled="@saving">
                @(saving ? "Saving..." : "Save")
            </button>

            @if (!string.IsNullOrEmpty(statusMessage))
            {
                <div class="alert alert-success mt-3">@statusMessage</div>
            }
        </div>

        <div class="col-md-6">
            <h5>Live Preview</h5>
            <div class="preview-box border rounded p-3"
                 style="@GetPreviewStyle()">
                <h6 style="margin-bottom:0.5rem;">Preview Area</h6>
                <p style="margin-bottom:0.5rem;">This is how your content will look with the selected settings.</p>
                <div class="d-flex gap-2 flex-wrap">
                    <button class="btn btn-sm btn-primary">Primary</button>
                    <button class="btn btn-sm btn-outline-secondary">Secondary</button>
                </div>
                <hr />
                <ul style="@(editCompactMode ? "margin:0;padding-left:1rem;" : "")">
                    <li>List item one</li>
                    <li>List item two</li>
                    <li>List item three</li>
                </ul>
            </div>
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public AppearanceSettings? Settings { get; set; }
    [Parameter, EditorRequired] public EventCallback<AppearanceSettings> OnSave { get; set; }

    private string editTheme = "Light";
    private string editFontSize = "Medium";
    private string editLanguage = "en";
    private bool editCompactMode;
    private bool saving;
    private string? statusMessage;

    protected override void OnParametersSet()
    {
        if (Settings is not null && !saving)
        {
            editTheme = Settings.Theme;
            editFontSize = Settings.FontSize;
            editLanguage = Settings.Language;
            editCompactMode = Settings.CompactMode;
        }
    }

    private string GetPreviewStyle()
    {
        var bg = editTheme switch
        {
            "Dark" => "background-color:#1e1e1e;color:#d4d4d4;",
            "System" => "background-color:#f0f0f0;color:#333;",
            _ => "background-color:#ffffff;color:#212529;"
        };

        var fs = editFontSize switch
        {
            "Small" => "font-size:0.8rem;",
            "Large" => "font-size:1.2rem;",
            _ => "font-size:1rem;"
        };

        var padding = editCompactMode ? "padding:0.5rem !important;" : "";

        return $"{bg}{fs}{padding}";
    }

    private async Task SaveAsync()
    {
        saving = true;
        statusMessage = null;
        var updated = new AppearanceSettings(editTheme, editFontSize, editLanguage, editCompactMode);
        await OnSave.InvokeAsync(updated);
        statusMessage = "Appearance settings saved!";
        saving = false;
    }
}
"}

