+
+<div class="settings-dashboard">
+    <SettingsSidebar ActiveSection="@activeSection"
+                     OnSectionChanged="section => activeSection = section" />
+
+    <div class="settings-content">
+        @switch (activeSection)
+        {
+            case "Profile":
+                <ProfileSection Profile="@profile" OnSave="SaveProfileAsync" />
+                break;
+            case "Notifications":
+                <NotificationsSection Prefs="@notificationPrefs" OnSave="SaveNotificationsAsync" />
+                break;
+            case "Security":
+                <SecuritySection Settings="@securitySettings"
+                                 OnChangePassword="HandleChangePasswordAsync"
+                                 OnToggleTwoFactor="HandleToggleTwoFactorAsync"
+                                 OnRevokeSession="HandleRevokeSessionAsync" />
+                break;
+            case "Appearance":
+                <AppearanceSection Settings="@appearanceSettings" OnSave="SaveAppearanceAsync" />
+                break;
+        }
+    </div>
+</div>
+
+@code {
+    private string activeSection = "Profile";
+
+    private UserProfile? profile;
+    private NotificationPrefs? notificationPrefs;
+    private SecuritySettings? securitySettings;
+    private AppearanceSettings? appearanceSettings;
+
+    protected override async Task OnInitializedAsync()
+    {
+        await LoadAllAsync();
+    }
+
+    private async Task LoadAllAsync()
+    {
+        var profileTask = SettingsService.GetProfileAsync();
+        var notifsTask = SettingsService.GetNotificationPrefsAsync();
+        var securityTask = SettingsService.GetSecuritySettingsAsync();
+        var appearanceTask = SettingsService.GetAppearanceAsync();
+
+        await Task.WhenAll(profileTask, notifsTask, securityTask, appearanceTask);
+
+        profile = profileTask.Result;
+        notificationPrefs = notifsTask.Result;
+        securitySettings = securityTask.Result;
+        appearanceSettings = appearanceTask.Result;
+    }
+
+    private async Task SaveProfileAsync(UserProfile updated)
+    {
+        await SettingsService.SaveProfileAsync(updated);
+        profile = updated;
+    }
+
+    private async Task SaveNotificationsAsync(NotificationPrefs updated)
+    {
+        await SettingsService.SaveNotificationPrefsAsync(updated);
+        notificationPrefs = updated;
+    }
+
+    private async Task HandleChangePasswordAsync((string CurrentPassword, string NewPassword) args)
+    {
+        await SettingsService.ChangePasswordAsync(args.CurrentPassword, args.NewPassword);
+        securitySettings = await SettingsService.GetSecuritySettingsAsync();
+    }
+
+    private async Task HandleToggleTwoFactorAsync()
+    {
+        // Reload security settings after toggling (actual toggle logic is in the service)
+        securitySettings = await SettingsService.GetSecuritySettingsAsync();
+    }
+
+    private async Task HandleRevokeSessionAsync(string sessionId)
+    {
+        await SettingsService.RevokeSessionAsync(sessionId);
+        securitySettings = await SettingsService.GetSecuritySettingsAsync();
+    }
+
+    private async Task SaveAppearanceAsync(AppearanceSettings updated)
+    {
+        await SettingsService.SaveAppearanceAsync(updated);
+        appearanceSettings = updated;
+    }
+}
+

