.settings-dashboard {
    display: flex;
    min-height: calc(100vh - 120px);
    gap: 0;
}

::deep .settings-sidebar {
    width: 220px;
    flex-shrink: 0;
    background-color: var(--bs-gray-100);
    border-right: 1px solid var(--bs-border-color);
    padding: 1rem 0;
}

::deep .settings-sidebar .nav-link {
    display: flex;
    align-items: center;
    gap: 0.5rem;
    padding: 0.75rem 1.25rem;
    color: var(--bs-body-color);
    border: none;
    background: none;
    width: 100%;
    text-align: left;
    font-size: 0.95rem;
    border-left: 3px solid transparent;
    transition: background-color 0.15s, border-color 0.15s;
}

::deep .settings-sidebar .nav-link:hover {
    background-color: var(--bs-gray-200);
}

::deep .settings-sidebar .nav-link.active {
    background-color: var(--bs-primary-bg-subtle);
    border-left-color: var(--bs-primary);
    color: var(--bs-primary);
    font-weight: 600;
}

::deep .sidebar-icon {
    font-size: 1.1rem;
}

.settings-content {
    flex: 1;
    padding: 1.5rem 2rem;
    overflow-y: auto;
}

::deep .settings-section h3 {
    font-weight: 600;
    margin-bottom: 0.25rem;
}

::deep .preview-box {
    min-height: 200px;
    transition: all 0.2s ease;
}

